import{c as o,Q as a,j as r,m as l}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"How Boris Uses Claude Code: A Comprehensive Guide","description":"","frontmatter":{"url":"https://howborisusesclaudecode.com/","title":"How Boris Uses Claude Code: A Comprehensive Guide","type":"article"},"headers":[],"relativePath":"research/ai-articles/12-howborisusesclaudecode.md","filePath":"research/ai-articles/12-howborisusesclaudecode.md","lastUpdated":1779796674000}'),s={name:"research/ai-articles/12-howborisusesclaudecode.md"};function i(t,e,d,c,u,n){return a(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="how-boris-uses-claude-code-a-comprehensive-guide" tabindex="-1">How Boris Uses Claude Code: A Comprehensive Guide <a class="header-anchor" href="#how-boris-uses-claude-code-a-comprehensive-guide" aria-label="Permalink to &quot;How Boris Uses Claude Code: A Comprehensive Guide&quot;">​</a></h1><p><strong>原始 URL</strong>: <a href="https://howborisusesclaudecode.com/" target="_blank" rel="noreferrer">https://howborisusesclaudecode.com/</a></p><p><strong>作者</strong>: Boris Cherny（Anthropic Claude Code 創造者）及團隊成員<br><strong>發佈日期</strong>: 自 2026 年 1 月 2 日起（持續更新至 2026 年 5 月）<br><strong>來源</strong>: X (Twitter) 執行緒與編譯網站</p><hr><h2 id="核心摘要" tabindex="-1">核心摘要 <a class="header-anchor" href="#核心摘要" aria-label="Permalink to &quot;核心摘要&quot;">​</a></h2><p>本資源彙編了 Boris Cherny 工作流程中的 89+ 實踐技巧，跨越 2026 年 1 月至 5 月多個執行緒。指南展示 Claude Code「開箱即用效果絕佳」，同時提供廣泛的客製化選項。核心理念是將 Claude Code 視為「平行執行引擎，而非聊天機器人」，強調前期規劃、持久知識建設與重複工作流程自動化。</p><h3 id="並行執行與效率" tabindex="-1">並行執行與效率 <a class="header-anchor" href="#並行執行與效率" aria-label="Permalink to &quot;並行執行與效率&quot;">​</a></h3><ul><li>使用分離的 git worktrees 同時運行 5+ Claude Code 實例</li><li>執行 <code>claude --worktree</code> 隔離平行會話</li><li>啟用自動模式以跳過權限提示，同時保持安全性</li></ul><h3 id="模型與配置" tabindex="-1">模型與配置 <a class="header-anchor" href="#模型與配置" aria-label="Permalink to &quot;模型與配置&quot;">​</a></h3><ul><li>所有任務使用 Opus 4.5 搭配思考模式，因其工具使用優越性</li><li>維護共享的 CLAUDE.md 檔案，記錄學習到的更正</li><li>在 PR 審查中標記 @.claude 自動更新文件</li></ul><h3 id="工作流程最佳化" tabindex="-1">工作流程最佳化 <a class="header-anchor" href="#工作流程最佳化" aria-label="Permalink to &quot;工作流程最佳化&quot;">​</a></h3><ul><li>複雜任務先從計畫模式開始，再轉為自動接受編輯</li><li>在 .claude/commands/ 中為重複工作流程儲存斜線命令</li><li>為常見 PR 自動化實作 subagents</li></ul><hr><h2 id="驗證與品質" tabindex="-1">驗證與品質 <a class="header-anchor" href="#驗證與品質" aria-label="Permalink to &quot;驗證與品質&quot;">​</a></h2><p><strong>關鍵洞察</strong>: 「給 Claude 一個驗證其工作的方法」能大幅改善結果</p><ul><li>使用 Chrome 擴展進行前端測試與迭代</li><li>跨不同域執行驗證迴圈</li></ul><hr><h2 id="進階功能" tabindex="-1">進階功能 <a class="header-anchor" href="#進階功能" aria-label="Permalink to &quot;進階功能&quot;">​</a></h2><p><strong>批次與迴圈自動化</strong></p><ul><li>使用 <code>/batch</code> 跨 worktrees 並行代碼遷移</li><li>配置 <code>/loop</code> 執行最長 3 天的重複任務（無人值守）</li><li>運用 <code>/goal</code> 讓 Claude 工作至完成條件達成</li></ul><p><strong>上下文管理</strong></p><ul><li>使用 <code>/rewind</code> 代替修正，避免污染上下文</li><li>區分 <code>/compact</code>（有損摘要）與 <code>/clear</code>（手動簡報）</li><li>設定 <code>CLAUDE_CODE_AUTO_COMPACT_WINDOW=400000</code> 避免上下文衰退</li></ul><hr><h2 id="關鍵引用與數據" tabindex="-1">關鍵引用與數據 <a class="header-anchor" href="#關鍵引用與數據" aria-label="Permalink to &quot;關鍵引用與數據&quot;">​</a></h2><blockquote><p>「將 Claude 視為委派的工程師，而非配對程序員」</p></blockquote><p><strong>並行執行規模</strong>: 5+ 同時 Claude Code 實例（git worktrees 隔離）<br><strong>自動模式</strong>: 啟用以跳過權限提示<br><strong>模型標準化</strong>: Opus 4.5 搭配思考模式所有任務<br><strong>驗證效果</strong>: 啟用自驗證迴圈可 2-3 倍提升最終品質</p><hr><h2 id="應用模式" tabindex="-1">應用模式 <a class="header-anchor" href="#應用模式" aria-label="Permalink to &quot;應用模式&quot;">​</a></h2><p>該指南強調治療 Claude 為委派的工程師而非聊天機器人，事前完整提供任務上下文包括目標、約束與驗收標準。技巧跨越平行執行、模型選擇、計畫模式優先、文件化、自定義命令、subagents、自動化 hooks、驗證迴圈與工具集成等領域。</p>',29)])])}const b=o(s,[["render",i]]);export{p as __pageData,b as default};
